@AndroidEntryPoint
class WeatherFragment : Fragment() {

    private var mainViewModel: MainViewModel? = null

    private val viewModel: WeatherViewModel by viewModels()

    override fun onAttach(context: Context) {
        super.onAttach(context)
        val activity = requireActivity()
        if (activity is MainActivity) {
            mainViewModel = activity.getMainViewModel()
        }
    }

    override fun onCreateView(
        inflater: LayoutInflater,
        container: ViewGroup?,
        savedInstanceState: Bundle?
    ): View {
        viewModel.subscribeNavigateAction()
        viewModel.subscribeTakeSnapshot()
        return ComposeView(requireContext()).apply {
            setViewCompositionStrategy(ViewCompositionStrategy.DisposeOnViewTreeLifecycleDestroyed)
            setContent {
                ComposeTheme {
                    Surface(modifier = Modifier.fillMaxSize()) {
                        val state by viewModel.viewState.collectAsState()
                        when (val uiModel = state) {
                            is WeatherUiModel -> {
                                WeatherScreen(
                                    uiModel = uiModel,
                                    onCameraPermissionResult = { allowed ->
                                        if (allowed) {
                                            takeSnapshot()
                                        } else {
                                            // show hint that the app should have this permission
                                            // we show settings screen after user reject the permission
                                            context.openPermissionSettings()
                                        }
                                    }
                                )
                            }

                            is LoadingUiModel -> {
                                LoadingScreen(uiModel = uiModel)
                            }

                            is ErrorUiModel -> {
                                ErrorScreen(
                                    uiModel = uiModel,
                                    onRetry = {
                                        viewModel.retry()
                                    }
                                )
                            }
                        }
                    }
                }
            }
        }
    }

    private fun subscribeViewActions() {
        logDebug("subscribe action")
        mainViewModel?.let { mainViewModel ->
            mainViewModel.viewAction.observe(viewLifecycleOwner) {
                when (it) {
                    is WeatherViewAction.TakeSnapshot -> onSnapshotTriggered()
                    else -> {
                        logError("Unhandled ViewAction: $it")
                    }
                }
            }
        }
    }

    private fun onSnapshotTriggered() {
        logDebug("Snapshot triggered")
        requestPermissionOrSnapshot()
    }

    private fun requestPermissionOrSnapshot() {
        if (hasPermission(cameraPermission)) {
            logDebug("Camera permission granted")
            takeSnapshot()
        } else {
            logDebug("Requesting camera permission")
            requestPermission(
                permission = cameraPermission,
                onPermissionRequest = { allowed ->
                    if (allowed) {
                        takeSnapshot()
                    } else {
                        // reject, ask again
                        showRationaleForCameraPermission()
                    }
                }
            )
        }
    }

    private fun showRationaleForCameraPermission() {
        logDebug("show rationale for camera permission")
        requestPermission(
            permission = cameraPermission,
            rationaleMessage = getString(R.string.permission_rationale_message),
            rationaleTitle = getString(R.string.permission_rationale_title),
            onPermissionRequest = { allowed ->
                logDebug("onPermissionRequest: $allowed")
                if (allowed) {
                    takeSnapshot()
                } else {
                    // show hint that the app should have this permission
                    // we show settings screen after user reject the permission
                    requireContext().openPermissionSettings()
                }
            }
        )
    }

    private fun takeSnapshot() {
        viewModel.dispatch(WeatherIntent.TakeSnapShot)
    }

    override fun onResume() {
        super.onResume()
        subscribeViewActions()
    }

    companion object {
        fun newInstance() = WeatherFragment()
    }
