import android.graphics.Bitmap
import androidx.lifecycle.viewModelScope
import com.howechen.weather.R
import com.howechen.weather.domain.entity.WeatherEntity
import com.howechen.weather.domain.usecase.snapshot.CreateSnapshotUseCase
import com.howechen.weather.domain.usecase.weather.WeatherSubscriptionUseCase
import com.howechen.weather.ui.BaseViewModel
import com.howechen.weather.ui.main.WeatherViewAction
import com.howechen.weather.util.logDebug
import com.howechen.weather.util.logError
import dagger.hilt.android.lifecycle.HiltViewModel
import kotlinx.coroutines.Job
import kotlinx.coroutines.flow.MutableStateFlow
import kotlinx.coroutines.flow.StateFlow
import kotlinx.coroutines.flow.catch
import kotlinx.coroutines.flow.collectLatest
import kotlinx.coroutines.flow.update
import kotlinx.coroutines.launch
import javax.inject.Inject

/**
 *
 * @author: Howe Chen
 * @email: howechen1989@gmail.com
 * @date: 05/10/2023
 *
 */
@HiltViewModel
class WeatherViewModel @Inject constructor(
    private val weatherSubscriptionUseCase: WeatherSubscriptionUseCase,
    private val createSnapshotUseCase: CreateSnapshotUseCase,
    private val weatherUiModelFactory: WeatherUiModelFactory,
) : BaseViewModel<WeatherUiModel, WeatherEffect, WeatherIntent>() {

    private val _viewState = MutableStateFlow<Weather>(LoadingUiModel())
    override val viewState: StateFlow<Weather> = _viewState

    private var weatherJob: Job? = null

    init {
        subScribeWeather()
    }

    override fun dispatch(intent: WeatherIntent) {
        when (intent) {
            is WeatherIntent.TakeSnapShot -> {
                onTakeSnapshot()
            }
        }
    }

    override fun subscribeTakeSnapshot() {
        viewActions?.let { flow ->
            viewModelScope.launch {
                flow.collectLatest { action ->
                    if (action is WeatherViewAction.TakeSnapshot) {
                        logDebug("receive take snapshot action")
                        onTakeSnapshot()
                    }
                }
            }
        }
    }

    private fun onTakeSnapshot() {
        // current state
        val uiModel = _viewState.value
        if (uiModel !is WeatherUiModel) {
            logError("Cannot take snapshot when state is $uiModel")
            return
        }

        // trigger take snapshot
        viewModelScope.launch {
            logDebug("Taking snapshot")
            _viewState.update { currentUiModel ->
                if (currentUiModel is WeatherUiModel) {
                    currentUiModel.copy(
                        isPhotoCaptureInProgress = true
                    )
                } else {
                    currentUiModel
                }
            }

            kotlin.runCatching {
                val bitmap = createSnapshotUseCase(
                    CreateSnapshotUseCase.Params(
                        uiModel.todayWeather.temperature.value.toInt(),
                        uiModel.todayWeather.weatherType.iconResId
                    )
                )
                onSnapshotCreated(bitmap)
            }.onFailure { e ->
                logError("Error in taking snapshot: $e")
                // clear photo capture state
                _viewState.update { currentUiModel ->
                    if (currentUiModel is WeatherUiModel) {
                        currentUiModel.copy(
                            isPhotoCaptureInProgress = false,
                            statusMessage = StatusMessage.SnapshotFailed
                        )
                    } else {
                        currentUiModel
                    }
                }
            }
        }
    }

    private fun onSnapshotCreated(bitmap: Bitmap) {
        logDebug("Snapshot taken")
        _viewState.update { currentUiModel ->
            if (currentUiModel is WeatherUiModel) {
                currentUiModel.copy(
                    snapshot = bitmap,
                    isPhotoCaptureInProgress = false,
                    statusMessage = StatusMessage.SnapshotSuccess
                )
            } else {
                currentUiModel
            }
        }
    }

    fun retry() {
        _viewState.update {
            LoadingUiModel()
        }
        subScribeWeather()
    }

    private fun subScribeWeather() {
        // Cancel existing job if any
        weatherJob?.cancel()

        weatherJob = viewModelScope.launch {
            weatherSubscriptionUseCase(Unit)
                .catch { error ->
                    logError("Error from weather subscription: $error")
                    _viewState.update {
                        ErrorUiModel(
                            errorMessage = R.string.something_went_wrong
                        )
                    }
                }
                .collectLatest {
                    onWeatherEntityReceived(it)
                }
        }
    }

    private fun onWeatherEntityReceived(weatherEntity: WeatherEntity) {
        logDebug("Weather entity received: $weatherEntity")
        val uiModel = weatherUiModelFactory.create(weatherEntity)
        _viewState.update {
            uiModel
        }
    }
