sealed interface Weather

data class WeatherUiModel(
    val todayWeather: TodayWeatherUiModel,
    val forecastWeather: List<ForecastWeatherUiModel>,
    val isPhotoCaptureInProgress: Boolean = false,
    val snapshot: Bitmap? = null,
    val statusMessage: StatusMessage? = null
) : Weather

data class TodayWeatherUiModel(
    val weatherType: WeatherType,
    val location: StringResource,
    val temperature: TemperatureUiModel,
    val isRain: Boolean,
    val wind: WindUiModel,
    val humidity: HumidityUiModel,
    val precipitationRisk: PrecipitationRiskUiModel?,
    val precipitationVolume: PrecipitationVolumeUiModel?,
)

data class ForecastWeatherUiModel(
    val day: StringResource,
    val weatherType: WeatherType,
    val temperature: TemperatureUiModel,
    val isRain: Boolean
)

data class TemperatureUiModel(
    val value: Double,
    val formatted: StringResource
)

data class WindUiModel(
    val value: Double,
    val formatted: StringResource
)

data class HumidityUiModel(
    val value: Int,
    val formatted: StringResource
)

data class PrecipitationRiskUiModel(
    val value: Int,
    val formatted: StringResource
)

data class PrecipitationVolumeUiModel(
    val value: Double,
    val formatted: StringResource
)

enum class WeatherType(val iconResId: Int) {
    SUNNY(R.drawable.ic_sun),
    RAINY(R.drawable.ic_rain),
    CLOUDY(R.drawable.ic_cloud),
    PARTLY_CLOUDY(R.drawable.ic_partly_cloudy),
    THUNDERSTORM(R.drawable.ic_thunderstorm),
    SNOWY(R.drawable.ic_snow),
    FOGGY(R.drawable.ic_foggy);

    companion object {
        fun from(type: String): WeatherType {
            return when (type.lowercase()) {
                "sunny" -> SUNNY
                "rainy" -> RAINY
                "cloudy" -> CLOUDY
                "partly_cloudy" -> PARTLY_CLOUDY
                "thunderstorm" -> THUNDERSTORM
                "snowy" -> SNOWY
                "foggy" -> FOGGY
                else -> {
                    logError("Unknown weather type: $type, defaulting to SUNNY")
                    SUNNY
                }
            }
        }
    }
}

data class LoadingUiModel(
    val isLoading: Boolean = true
) : Weather

data class ErrorUiModel(
    @StringRes val errorMessage: Int
) : Weather

sealed class StatusMessage(@StringRes val text: Int) {
    data object SnapshotSuccess : StatusMessage(R.string.snapshot_success)
    data object SnapshotFailed : StatusMessage(R.string.snapshot_failed)
}

class WeatherUiModelFactory @Inject constructor() {

    fun create(weatherEntity: WeatherEntity): WeatherUiModel {
        val currentWeather = weatherEntity.todayWeather
        val forecastWeather = weatherEntity.forecastWeather

        return WeatherUiModel(
            todayWeather = TodayWeatherUiModel(
                weatherType = WeatherType.from(currentWeather.weatherType),
                location = StringResource.Simple(currentWeather.location),
                temperature = TemperatureUiModel(
                    value = currentWeather.temperature,
                    formatted = StringResource.WithArgs(
                        R.string.temperature_formatted,
                        formatSymbolValue(currentWeather.temperature)
                    )
                ),
                isRain = currentWeather.isRain,
                wind = WindUiModel(
                    value = currentWeather.wind,
                    formatted = StringResource.WithArgs(
                        R.string.wind_formatted,
                        formatSymbolValue(currentWeather.wind)
                    )
                ),
                humidity = HumidityUiModel(
                    value = currentWeather.humidity,
                    formatted = StringResource.WithArgs(
                        R.string.humidity_formatted,
                        currentWeather.humidity.toString()
                    )
                ),
                precipitationRisk = currentWeather.precipitationRisk?.let {
                    PrecipitationRiskUiModel(
                        value = it,
                        formatted = StringResource.WithArgs(
                            R.string.precipitation_risk_formatted,
                            it.toString()
                        )
                    )
                },
                precipitationVolume = currentWeather.precipitationVolume?.let {
                    PrecipitationVolumeUiModel(
                        value = it,
