    }

fun Fragment.hasPermission(permission: String): Boolean {
    return ContextCompat.checkSelfPermission(
        requireContext(),
        permission
    ) == PackageManager.PERMISSION_GRANTED
}

fun Fragment.requestPermission(
    permission: String,
    rationaleTitle: String? = null,
    rationaleMessage: String? = null,
    onPermissionRequest: (Boolean) -> Unit
) {
    logDebug("Requesting permission $permission")
    val requestPermissionLauncher = registerForActivityResult(
        ActivityResultContracts.RequestPermission()
    ) { isGranted ->
        logDebug("Permission $permission granted: $isGranted")
        onPermissionRequest(isGranted)
    }

    val shouldShowRationale = shouldShowRequestPermissionRationale(permission)
    when {
        shouldShowRationale && rationaleMessage != null && rationaleTitle != null -> {
            showPermissionRationaleDialog(
                rationaleTitle,
                rationaleMessage,
                requestPermissionLauncher,
                permission
            )
        }
        else -> {
            requestPermissionLauncher.launch(permission)
        }
    }
}

fun Fragment.showPermissionRationaleDialog(
    title: String,
    message: String,
    requestPermissionLauncher: ActivityResultLauncher<String>,
    permission: String
) {
    logDebug("Showing rationale dialog for permission $permission")
    AlertDialog.Builder(requireContext())
        .setTitle(title)
        .setMessage(message)
        .setPositiveButton(android.R.string.ok) { _, _ ->
            requestPermissionLauncher.launch(permission)
        }
        .setNegativeButton(android.R.string.cancel) { _, _ ->
            logDebug("User declined to request permission $permission after rationale")
            // User declined after seeing rationale
        }
        .create()
        .show()
}

fun Context.openPermissionSettings() {
    logDebug("Opening permission settings")
    Intent(Settings.ACTION_APPLICATION_DETAILS_SETTINGS).apply {
        data = Uri.fromParts("package", packageName, null)
        addFlags(Intent.FLAG_ACTIVITY_NEW_TASK)
        startActivity(this)
    }
