sealed class StringResource {

    data class Simple(val value: String) : StringResource()

    data class WithArgs(
        @StringRes val resId: Int,
        vararg val args: Any
    ) : StringResource()

    fun text(context: Context): String {
        return when (this) {
            is Simple -> this.value
            is WithArgs -> context.getString(this.resId, *this.args)
        }
    }

    @Composable
    fun text(): String {
        return when (this) {
            is Simple -> this.value
            is WithArgs -> stringResource(id = this.resId, *this.args)
        }
    }
}

/**
 * Format a numeric value with a symbol and one decimal place if needed
 * Examples:
 * - 10.0 -> "10°"
 * - 10.5 -> "10.5°"
 */
fun formatSymbolValue(value: Double, symbol: String = "°"): String {
    return if (value % 1 == 0.0) {
        // It's a whole number
        "${value.toInt()}$symbol"
    } else {
        // Has decimal part
        String.format("%.1f", value) + symbol
    }
