import javax.inject.Inject

/**
 *
 * @author: Howe Chen
 * @email: howechen1989@gmail.com
 * @date: 06/10/2023
 *
 */

class CreateSnapshotUseCase @Inject constructor() : UseCase<CreateSnapshotUseCase.Params, Bitmap>() {

    companion object {
        private const val DEFAULT_WIDTH = 800
        private const val DEFAULT_HEIGHT = 400
        private const val TEXT_SIZE = 80f
        private const val TEXT_PADDING = 40
    }

    data class Params(
        val temperature: Int,
        val iconResourceId: Int
    )

    override suspend fun execute(params: Params): Bitmap {
        try {
            return createBitmap(params.temperature, params.iconResourceId)
        } catch (e: Exception) {
            logError("Error creating bitmap: $e")
            throw e
        }
    }

    private fun createBitmap(temperature: Int, iconResourceId: Int): Bitmap {
        // Create a bitmap
        val bitmap = Bitmap.createBitmap(DEFAULT_WIDTH, DEFAULT_HEIGHT, Bitmap.Config.ARGB_8888)
        val canvas = Canvas(bitmap)

        // Set background color
        canvas.drawColor(Color.rgb(240, 240, 240)) // Light gray background

        // Create text paint
        val textPaint = Paint().apply {
            color = Color.BLACK
            textSize = TEXT_SIZE
            typeface = Typeface.create(Typeface.DEFAULT, Typeface.BOLD)
            isAntiAlias = true
        }

        // Measure text
        val temperatureText = formatSymbolValue(temperature.toDouble())
        val bounds = Rect()
        textPaint.getTextBounds(temperatureText, 0, temperatureText.length, bounds)

        // Calculate center position for text
        val x = (bitmap.width - bounds.width()) / 2f
        val y = (bitmap.height + bounds.height()) / 2f

        // Draw text
        canvas.drawText(temperatureText, x, y, textPaint)

        // Draw timestamp at the bottom
        val timestampPaint = Paint().apply {
            color = Color.GRAY
            textSize = TEXT_SIZE / 3
            isAntiAlias = true
        }
        val timestamp = "Captured: ${System.currentTimeMillis()}"
        canvas.drawText(
            timestamp,
            TEXT_PADDING.toFloat(),
            bitmap.height - TEXT_PADDING.toFloat(),
            timestampPaint
        )

        return bitmap
    }
