    private lateinit var weatherSubscriptionUseCase: WeatherSubscriptionUseCase

    @Before
    fun setUp() {
        weatherSubscriptionUseCase = WeatherSubscriptionUseCase(weatherRepository)
    }

    @Test
    fun `test success subscription`() = runTest {
        // Prepare mock data
        val mockWeatherEntity = MockWeatherEntity.create()
        coEvery { weatherRepository.getWeather() } returns flow {
            emit(mockWeatherEntity)
        }

        // Execute use case
        val result = weatherSubscriptionUseCase(Unit).toList()

        // Verify repository was called
        coVerify { weatherRepository.getWeather() }

        // Verify correct data was emitted
        assertEquals(1, result.size)
        assertEquals(mockWeatherEntity, result[0])
    }

    @Test
    fun `test multiple emissions`() = runTest {
        // Prepare mock data with multiple emissions
        val mockWeatherEntity1 = MockWeatherEntity.create()
        val mockWeatherEntity2 = MockWeatherEntity.create().copy(
            todayWeather = mockWeatherEntity1.todayWeather.copy(temperature = 22.0)
        )

        coEvery { weatherRepository.getWeather() } returns flow {
            emit(mockWeatherEntity1)
            emit(mockWeatherEntity2)
        }

        // Execute use case
        val result = weatherSubscriptionUseCase(Unit).toList()

        // Verify repository was called
        coVerify { weatherRepository.getWeather() }

        // Verify both emissions were collected
        assertEquals(2, result.size)
        assertEquals(mockWeatherEntity1, result[0])
        assertEquals(mockWeatherEntity2, result[1])
    }

    @Test
    fun `test error handling`() = runTest {
        // Prepare mock error
        val mockError = RuntimeException("Network error")
        coEvery { weatherRepository.getWeather() } returns flow {
            throw mockError
        }

        // Execute use case and expect the error to be propagated
        assertFailsWith<RuntimeException> {
            weatherSubscriptionUseCase(Unit).toList()
        }

        // Verify repository was called
        coVerify { weatherRepository.getWeather() }
    }
