#pragma once

constexpr const int TILE_DIM = 32;
constexpr const int  BLOCK_ROWS = 8;

template<typename VT>
__global__ void transposeKernel(VT* odata, const VT* idata, int64_t width, int64_t height) {
    __shared__ VT tile[TILE_DIM][TILE_DIM+1];

    int64_t x = blockIdx.x * TILE_DIM + threadIdx.x;
    int64_t y = blockIdx.y * TILE_DIM + threadIdx.y;
    int64_t width_x = gridDim.x * TILE_DIM;

    for(int64_t j = 0; j < TILE_DIM && y + j < height; j+= BLOCK_ROWS)
    {
        tile[threadIdx.y+j][threadIdx.x] = idata[(y+j)*width + x];
    }

    __syncthreads();

    x = blockIdx.y * TILE_DIM + threadIdx.x; // transpose block offset
    y = blockIdx.x * TILE_DIM + threadIdx.y;

    for(int64_t j = 0; j < TILE_DIM && y + j < width_x; j += BLOCK_ROWS)
    {
        if(x < height && y + j < width)
        {
            odata[(y+j)*height + x] = tile[threadIdx.x][threadIdx.y+j];
        }
    }
}
