    namespace {
        template<typename VT>
        struct transform_row_sum {
            VT*  _array;
            size_t _n_col;

            __host__ __device__
            transform_row_sum(VT* array, size_t n_col) : _array(array), _n_col(n_col) {}

            __host__ __device__
            VT operator()(const size_t& i) const {
                VT sum{};
                for(size_t j = 0; j < _n_col; ++j) {
                    sum += _array[i * _n_col + j];
                }
                return sum;
            }
        };

        template<typename VT>
        struct transform_row_means {
            VT*  _array;
            size_t _n_col;

            __host__ __device__
            transform_row_means(VT* array, size_t n_col) : _array(array), _n_col(n_col) {}

            __host__ __device__
            VT operator()(const size_t& i) const {
                VT sum{};
                for(size_t j = 0; j < _n_col; ++j) {
                    sum += _array[i * _n_col + j];
                }
                return sum / _n_col;
            }
        };

        template<typename VT>
        struct transform_col_sum {
            VT*  _array;
            size_t _n_row;
            size_t _n_col;

            __host__ __device__
            transform_col_sum(VT* array, size_t n_row, size_t n_col) : _array(array), _n_row(n_row), _n_col(n_col) {}

            __host__ __device__
            VT operator()(const size_t& j) const {
                VT sum{};
                for(size_t i = 0; i < _n_row; ++i) {
                    sum += _array[i * _n_col + j];
                }
                return sum;
            }
        };

        template<typename VT>
        struct transform_col_means {
            VT*  _array;
            size_t _n_row;
            size_t _n_col;

            __host__ __device__
            transform_col_means(VT* array, size_t n_row, size_t n_col) : _array(array), _n_row(n_row), _n_col(n_col) {}

            __host__ __device__
            VT operator()(const size_t& j) const {
                VT sum{};
                for(size_t i = 0; i < _n_row; ++i) {
                    sum += _array[i * _n_col + j];
                }
                return sum / _n_row;
            }
        };

    } // anonymous namespace

    cudaStream_t createStream(){
        cudaStream_t stream;
        cudaStreamCreate(&stream);
        return stream;
    }

    template<typename VT>
    void row_means(const cudaStream_t& stream, VT* in, size_t numRows, size_t numCols, VT* out) {
        thrust::transform(
            thrust::cuda::par.on(stream),
            thrust::make_counting_iterator<size_t>(0),
            thrust::make_counting_iterator<size_t>(numRows),
            out,
            transform_row_means<VT>(in, numCols)
        );
    }

    template<typename VT>
    void col_means(const cudaStream_t& stream, VT* in, size_t numRows, size_t numCols, VT* out) {
        thrust::transform(
            thrust::cuda::par.on(stream),
            thrust::make_counting_iterator<size_t>(0),
            thrust::make_counting_iterator<size_t>(numCols),
            out,
            transform_col_means<VT>(in, numRows, numCols)
        );
    }

