        if(in->getNumRows() != out->getNumCols() || in->getNumCols() != out->getNumRows())
            throw std::runtime_error("Matrix dimensions for transpose do not match");

        dim3 grid, block;
        block.x = TILE_DIM;
        block.y = BLOCK_ROWS;
        grid.x = (in->getNumCols() + TILE_DIM - 1) / TILE_DIM;
        grid.y = (in->getNumRows() + TILE_DIM - 1) / TILE_DIM;

        transposeKernel<<<grid, block, 0, stream>>>(out->getData(), in->getData(), in->getNumCols(), in->getNumRows());

        cudaError_t error = cudaGetLastError();

        if (error != cudaSuccess)
            throw std::runtime_error("CUDA Transpose failed");
    }

    template <typename T>
    void evaluate(DCTX(ctx), const Matrix<T> *mat1, Matrix<T> *mat2) {
        if(mat1->getNumRows() != mat2->getNumCols() || mat1->getNumCols() != mat2->getNumRows())
            throw std::runtime_error("Matrix dimensions for transpose do not match");

        // create CUDA matrics from Matrix pointers
        CUDAMatrix<T> *in = nullptr;

        if (auto cm1 = dynamic_cast<const CUDAMatrix<T>*>(mat1)) {
                in = const_cast<CUDAMatrix<T>*>(cm1);
        } else {
            in = new CUDAMatrix<T>(mat1->getNumRows(), mat1->getNumCols(), false, CUDA::CUDAMatrixMemoryLayout::ROW_MAJOR, ctx);

        for(size_t r = 0; r < mat1->getNumRows(); ++r) {
            for(size_t c = 0; c < mat1->getNumCols(); ++c) {
                in->setElement(r, c, mat1->get(r, c, ctx), ctx);
            }
        }
    }

    // create CUDA matrics from Matrix pointers
    CUDAMatrix<T> *out = nullptr;

    if (auto cm2 = dynamic_cast<CUDAMatrix<T>*>(mat2)) {
            out = cm2;
    } else {
        out = new CUDAMatrix<T>(mat2->getNumRows(), mat2->getNumCols(), false, CUDA::CUDAMatrixMemoryLayout::ROW_MAJOR, ctx);
    }

    cudaStream_t stream = CUDA::Transaction::getStream(ctx);

    try{
        evaluate(in, out, stream);
    }catch(std::runtime_error &e){
        std::cout << "Error: " << e.what() << std::endl;
    }

    // copy data back
    // copy back data
    if (!dynamic_cast<CUDAMatrix<T>*>(mat2)) {
        for(size_t r = 0; r < mat2->getNumRows(); ++r) {
            for(size_t c = 0; c < mat2->getNumCols(); ++c) {
                mat2->set(r, c, out->get(r, c, ctx), ctx);
            }
        }
    }

    // free matrices
    if (!dynamic_cast<const CUDAMatrix<T>*>(mat1) && in) {
        delete in;
    }
    if (!dynamic_cast<CUDAMatrix<T>*>(mat2) && out) {
        delete out;
    }

    cudaStreamSynchronize(stream);
    }

