namespace CUDA::UnaryOp {
    template<typename OP, typename VT>
    void evaluate(const UnaryOperator<OP, VT>& op, CUDAMatrix<VT>* lhs, Matrix<typename OP::output_t>* out, cudaStream_t stream) {
        if constexpr(std::is_same_v<OP, CUDA::OP_ROW_MEANS>) {
            using OUT_VT = typename OP::output_t;
            auto outcuda = dynamic_cast<CUDAMatrix<OUT_VT>*>(out);
            if(outcuda == nullptr)
                throw std::runtime_error("Output matrix must be a CUDAMatrix in CUDA::UnaryOp");
            row_means(stream, lhs->getData(), lhs->getNumRows(), lhs->getNumCols(), outcuda->getData());
        }
        else if constexpr(std::is_same_v<OP, CUDA::OP_COL_MEANS>) {
            using OUT_VT = typename OP::output_t;
            auto outcuda = dynamic_cast<CUDAMatrix<OUT_VT>*>(out);
            if(outcuda == nullptr)
                throw std::runtime_error("Output matrix must be a CUDAMatrix in CUDA::UnaryOp");
            col_means(stream, lhs->getData(), lhs->getNumRows(), lhs->getNumCols(), outcuda->getData());
        }
        else {
            throw std::runtime_error("Unsupported operation in CUDA::UnaryOp");
        }
    }

    template void evaluate<CUDA::OP_ROW_MEANS, float>(const UnaryOperator<CUDA::OP_ROW_MEANS, float>&, CUDAMatrix<float>*, Matrix<float>*, cudaStream_t);
    template void evaluate<CUDA::OP_ROW_MEANS, double>(const UnaryOperator<CUDA::OP_ROW_MEANS, double>&, CUDAMatrix<double>*, Matrix<double>*, cudaStream_t);
    template void evaluate<CUDA::OP_COL_MEANS, float>(const UnaryOperator<CUDA::OP_COL_MEANS, float>&, CUDAMatrix<float>*, Matrix<float>*, cudaStream_t);
    template void evaluate<CUDA::OP_COL_MEANS, double>(const UnaryOperator<CUDA::OP_COL_MEANS, double>&, CUDAMatrix<double>*, Matrix<double>*, cudaStream_t);
}

