                    TAB_STOPWATCH -> R.drawable.ic_stopwatch_vector
                    TAB_TIMER -> R.drawable.ic_timer_vector
                    else -> 0
                }

                val drawable = getDrawableById(drawableId)?.apply {
                    applyColorFilter(textColor)
                }
                tabsImageHolder[index].setImageDrawable(drawable)
                holder.beVisible()

                // hide tab divider if we are at the end
                if (index == lastFragmentIndex && tabCount > 1) {
                    holder.findViewById<ImageView>(R.id.tab_divider).beGone()
                } else {
                    holder.findViewById<ImageView>(R.id.tab_divider).beVisible()
                }

                if (tabCount == 1) {
                    holder.findViewById<ImageView>(R.id.tab_divider).beGone()
                }
            } else {
                holder.beGone()
            }
        }

        val isRtl = getResources().getBoolean(R.bool.is_rtl)
        val isDarkMode = isNightMode()
        val theme = getThemeId()
        val isDefaultIconActive = if (isDefaultAppIcon(this)) {
            !isDarkMode
        } else {
            config.appIconColor == APP_ICON_DEFAULT
        }

        if (!isDefaultIconActive && !isDarkMode && config.appIconColor == APP_ICON_SIMPLE && (theme == R.style.AppTheme || theme == R.style.AppTheme_White)) {
            binding.mainToolbar.setNavigationIconTint(getResources().getColor(R.color.md_grey_black))
        }

        val adjustedPrimaryColor = getProperPrimaryColor()
        if (binding.viewPager.adapter == null) {
            binding.viewPager.adapter = ViewPagerAdapter(supportFragmentManager)
            binding.viewPager.currentItem = config.lastUsedViewPagerPage
        }

        binding.viewPager.setBackgroundColor(getProperBackgroundColor())
        window.statusBarColor = getProperStatusBarColor()
        window.navigationBarColor = getProperBackgroundColor()

        updateLeftArrow()
        updateRightArrow()
        binding.tabsDash.background = ColorDrawable(getProperBackgroundColor())
        binding.tabsHolder.background = ColorDrawable(getProperBackgroundColor())
        binding.tabsHolder.beGoneIf(isRtl)
        binding.tabsHolderRtl.beGoneIf(!isRtl)
    }

    private fun setupOptionsMenu() {
        binding.mainToolbar.setNavigationIconVisible(false)
        binding.mainToolbar.setOnMenuItemClickListener { menuItem ->
            when (menuItem.itemId) {
                R.id.settings -> startActivity(Intent(applicationContext, SettingsActivity::class.java))
                R.id.change_app_icon -> changeAppIcon()
                else -> return@setOnMenuItemClickListener false
            }
            return@setOnMenuItemClickListener true
        }
    }

    private fun updateLeftArrow() {
        binding.tabsLeftArrow.apply {
            beVisibleIf(binding.viewPager.currentItem > 0)
            setOnClickListener {
                binding.viewPager.currentItem--
            }
        }
    }

    private fun updateRightArrow() {
        binding.tabsRightArrow.apply {
            val tabsCount = tabsList.filter { it and config.displayedTabs != 0 }.size
            beVisibleIf(tabsCount > 1 && binding.viewPager.currentItem < tabsCount - 1)
            setOnClickListener {
                binding.viewPager.currentItem++
            }
        }
    }

    private fun changeAppIcon() {
        if (!isOrWasThankYouInstalled()) {
            ConfirmationDialog(
                activity = this,
                messageId = R.string.features_locked,
                positive = R.string.purchase,
                negative = R.string.later
            ) {
                launchPurchase()
            }
        } else {
            ChangeAppIconDialog(this)
        }
    }

    private fun setupTabColors() {
        val activeView = when (binding.viewPager.currentItem) {
            0 -> binding.tabsClock
            1 -> binding.tabsAlarm
            2 -> binding.tabsStopwatch
            else -> binding.tabsTimer
        }
        updateProperTabsClip()
        tabsTabsHolder.forEach {
            it.setBackgroundColor(getProperBackgroundColor())
        }

        activeView?.background = ColorDrawable(getProperBackgroundColor())
        val activeFragmentText = tabsTextHolder.getOrNull(getActiveFragment())
        activeFragmentText?.setTextColor(getProperPrimaryColor())
        val activeFragmentIcon = tabsImageHolder.getOrNull(getActiveFragment())
        activeFragmentIcon?.drawable?.applyColorFilter(getProperPrimaryColor())
        tabsTextHolder.forEachIndexed { index, textView ->
            if (index != getActiveFragment()) {
                textView.setTextColor(getProperTextColor())
            }
        }
        tabsImageHolder.forEachIndexed { index, imageView ->
            if (index != getActiveFragment()) {
                imageView.drawable?.applyColorFilter(getProperTextColor())
            }
        }
    }

    private fun getActiveFragment(): Int {
        val displayedTabs = ArrayList<Int>()
        tabsList.forEachIndexed { _, value ->
            if (value and config.displayedTabs != 0) {
                displayedTabs.add(value)
            }
        }
        val fragments = arrayListOf(
            TAB_CLOCK,
            TAB_ALARM,
            TAB_STOPWATCH,
            TAB_TIMER
        )

        return fragments.indexOf(displayedTabs[binding.viewPager.currentItem])
    }

    private fun setupTabs() {
        binding.mainToolbar.menu.apply {
            findItem(R.id.settings).isVisible = true
            findItem(R.id.change_app_icon).isVisible = true
        }

        tabsTabsHolder = arrayListOf(binding.tabsClock, binding.tabsAlarm, binding.tabsStopwatch, binding.tabsTimer)
        tabsImageHolder = arrayListOf(binding.tabsClockIcon, binding.tabsAlarmIcon, binding.tabsStopwatchIcon, binding.tabsTimerIcon)
        tabsTextHolder = arrayListOf(binding.tabsClockLabel, binding.tabsAlarmLabel, binding.tabsStopwatchLabel, binding.tabsTimerLabel)

        // clock
        binding.tabsClock.setOnClickListener {
            binding.viewPager.currentItem = tabsList.indexOf(TAB_CLOCK)
        }
        binding.tabsClock.beVisibleIf(TAB_CLOCK and config.displayedTabs != 0)
        AutofitHelper.create(binding.tabsClockLabel)

        // alarm
        binding.tabsAlarm.setOnClickListener {
            binding.viewPager.currentItem = 1
        }
        binding.tabsAlarm.beVisibleIf(TAB_ALARM and config.displayedTabs != 0)
        AutofitHelper.create(binding.tabsAlarmLabel)

        // stopwatch
        binding.tabsStopwatch.setOnClickListener {
            binding.viewPager.currentItem = tabsList.indexOf(TAB_STOPWATCH)
        }
        binding.tabsStopwatch.beVisibleIf(TAB_STOPWATCH and config.displayedTabs != 0)
        AutofitHelper.create(binding.tabsStopwatchLabel)

        // timer
        binding.tabsTimer.setOnClickListener {
            binding.viewPager.currentItem = tabsList.indexOf(TAB_TIMER)
        }
        binding.tabsTimer.beVisibleIf(TAB_TIMER and config.displayedTabs != 0)
        AutofitHelper.create(binding.tabsTimerLabel)

        binding.tabsClockIcon.beVisibleIf(config.showTabIcon)
        binding.tabsAlarmIcon.beVisibleIf(config.showTabIcon)
        binding.tabsStopwatchIcon.beVisibleIf(config.showTabIcon)
        binding.tabsTimerIcon.beVisibleIf(config.showTabIcon)

        binding.tabsClockLabel.beVisibleIf(config.showTabLabel)
        binding.tabsAlarmLabel.beVisibleIf(config.showTabLabel)
        binding.tabsStopwatchLabel.beVisibleIf(config.showTabLabel)
        binding.tabsTimerLabel.beVisibleIf(config.showTabLabel)
    }

    private fun updateProperTabsClip() {
        if (isRTLLayout) {
            updateTabsRTL()
        } else {
            updateTabs()
        }
    }

    private fun updateTabs() {
        arrayOf(binding.tabsClock, binding.tabsAlarm, binding.tabsStopwatch, binding.tabsTimer).forEach {
            it.layoutParams.width = ViewGroup.LayoutParams.WRAP_CONTENT
        }
    }

    private fun updateTabsRTL() {
        arrayOf(binding.tabsClockRtl, binding.tabsAlarmRtl, binding.tabsStopwatchRtl, binding.tabsTimerRtl).forEach {
            it.layoutParams.width = ViewGroup.LayoutParams.WRAP_CONTENT
        }
    }

    private fun updateDateTime() {
        val calendar = Calendar.getInstance()
        val now = DateTime()
        val currentDay = calendar.get(Calendar.DAY_OF_MONTH)
        val currentMonthDay = "${getMonthName(now)}  $currentDay"
        binding.date.text = currentMonthDay

        val offset = getFormattedTime(System.currentTimeMillis())
        binding.time.text = offset

        if (config.selectedTimeZonesTitle.size > 1) {
            binding.timeAmerican.beVisible()
            var minuteOffset = -1
            var hourOffset = -1
            val currentDateTime = DateTime()
            val localTimeZone = config.selectedTimeZones.firstOrNull {
                minuteOffset = abs(TimeZone.getTimeZone(it).getOffset(currentDateTime.millis) / 60000)
                hourOffset = minuteOffset / 60
                minuteOffset -= hourOffset * 60
                return@firstOrNull it == TimeZone.getDefault().id
            }

            if (localTimeZone != null) {
                binding.timeAmerican.text = getFormattedOffset(hourOffset, minuteOffset)
            } else {
                binding.timeAmerican.text = "+00:00"
            }
        } else {
            binding.timeAmerican.beGone()
        }

        binding.date.text = getFormattedDate(DateTime().millis)
    }

    private fun getMonthName(dateTime: DateTime) = getString(
        when (dateTime.monthOfYear) {
            1 -> R.string.january
            2 -> R.string.february
            3 -> R.string.march
            4 -> R.string.april
            5 -> R.string.may
            6 -> R.string.june
            7 -> R.string.july
            8 -> R.string.august
            9 -> R.string.september
            10 -> R.string.october
            11 -> R.string.november
            12 -> R.string.december
            else -> R.string.january
        }
    )

    private fun setupTimer() {
        Thread {
            runOnUiThread {
                if (!isDestroyed && !isFinishing) {
                    updateDateTime()
                }
                setupTimer()
            }
            Thread.sleep(1000)
        }.start()
    }

    private fun getTabsMask(): Int {
        val allTabs = ALL_TABS_MASK
        return allTabs.takeIf { config.displayedTabs == 0 } ?: config.displayedTabs
    }

    private fun storeStateVariables() {
        config.apply {
            storedDayCode = getFormattedDate(System.currentTimeMillis())
            if (displayedTabs == 0) {
                displayedTabs = getTabsMask()
            }
        }
    }

    private fun getFormattedOffset(hourOffset: Int, minuteOffset: Int): String {
        val offset = "${hourOffset.toString().padStart(2, '0')}:${minuteOffset.toString().padStart(2, '0')}"
        return if (hourOffset >= 0) "+$offset" else offset
    }
}

