package com.simplemobiletools.clock.activities

import android.app.PendingIntent
import android.appwidget.AppWidgetManager
import android.appwidget.AppWidgetProvider
import android.content.ComponentName
import android.content.Context
import android.content.Intent
import android.graphics.Bitmap
import android.graphics.Canvas
import android.graphics.Color
import android.widget.RemoteViews
import com.simplemobiletools.clock.R
import com.simplemobiletools.clock.extensions.config
import com.simplemobiletools.clock.extensions.getFormattedDate
import com.simplemobiletools.clock.extensions.getTimeFormat
import com.simplemobiletools.commons.extensions.applyColorFilter
import com.simplemobiletools.commons.extensions.getLaunchIntent
import com.simplemobiletools.commons.extensions.setBackgroundColor
import org.joda.time.DateTime
import java.util.Calendar

class DigitalWidget : AppWidgetProvider() {
    override fun onUpdate(context: Context, appWidgetManager: AppWidgetManager, appWidgetIds: IntArray) {
        performUpdate(context)
    }

    private fun performUpdate(context: Context) {
        val appWidgetManager = AppWidgetManager.getInstance(context) ?: return
        appWidgetManager.getAppWidgetIds(getComponentName(context)).forEach {
            RemoteViews(context.packageName, R.layout.widget_digital).apply {
                updateTexts(context, this)
                updateColors(context, this)
                setupAppOpenIntent(context, this)
                appWidgetManager.updateAppWidget(it, this)
            }
        }
    }

    private fun updateTexts(context: Context, views: RemoteViews) {
        val timeFormat = context.getTimeFormat()
        val calendar = Calendar.getInstance()
        val currentHour = calendar.get(Calendar.HOUR_OF_DAY)
        val currentMinute = calendar.get(Calendar.MINUTE)
        var currentTime = DateTime().toString(timeFormat)
        if (currentHour == 0 && currentMinute == 0 || currentHour == 12 && currentMinute == 0) {
            currentTime = currentTime.replace("0:00", "12:00")
            currentTime = currentTime.replace("00:00", "12:00")
        }

        views.setTextViewText(R.id.time, currentTime)
        views.setTextViewText(R.id.date, context.getFormattedDate(calendar.timeInMillis))
    }

    private fun updateColors(context: Context, views: RemoteViews) {
        val config = context.config
        val widgetTextColor = config.widgetTextColor

        views.setTextColor(R.id.time, widgetTextColor)
        views.setTextColor(R.id.date, widgetTextColor)

        val bitmap = getColoredIcon(context, widgetTextColor)
        views.setImageViewBitmap(R.id.widget_background, bitmap)
    }

    private fun getColoredIcon(context: Context, color: Int): Bitmap {
        val options = context.resources.getDrawable(R.drawable.ic_clock_vector)
        val filter = Color.parseColor("#aa000000")
        val size = context.resources.getDimension(R.dimen.widget_icon_size).toInt()
        val bitmap = Bitmap.createBitmap(size, size, Bitmap.Config.ARGB_8888)
        val canvas = Canvas(bitmap)

        options.apply {
            setBounds(0, 0, size, size)
            applyColorFilter(color)
            setBackgroundColor(filter)
            draw(canvas)
        }

        return bitmap
    }

    private fun getComponentName(context: Context) = ComponentName(context, this::class.java)

    private fun setupAppOpenIntent(context: Context, views: RemoteViews) {
        val pendingIntent = PendingIntent.getActivity(context, 0, context.getLaunchIntent(), PendingIntent.FLAG_IMMUTABLE)
        views.setOnClickPendingIntent(R.id.widget_date_time_holder, pendingIntent)
    }

    override fun onEnabled(context: Context) {
        super.onEnabled(context)
        context.config.widgetsCount++
    }

    override fun onDisabled(context: Context) {
        super.onDisabled(context)
        context.config.widgetsCount--
    }
}

