import com.simplemobiletools.clock.R
import com.simplemobiletools.clock.databinding.ActivityHandsAdjustmentBinding
import com.simplemobiletools.clock.extensions.config
import com.simplemobiletools.clock.helpers.CUSTOM_SECONDS_TO_RESET
import com.simplemobiletools.clock.helpers.HANDS_FACE_BITMAP
import com.simplemobiletools.clock.helpers.HANDS_HANDS_BITMAP
import com.simplemobiletools.clock.helpers.HANDS_RECOLOR_TIMESTAMP
import com.simplemobiletools.clock.helpers.HANDS_WATCHES_FRAMES_BITMAP
