import com.simplemobiletools.commons.helpers.isSPlus
import com.squareup.picasso.Picasso
import java.util.Calendar
import kotlin.math.abs
import kotlin.math.roundToInt

class HandsAdjustmentActivity : SimpleActivity(), SensorEventListener {
    private val binding by viewBinding(ActivityHandsAdjustmentBinding::inflate)
    private var sensorManager: SensorManager? = null
    private var accelerometer: Sensor? = null
    private var currentDegree = 0f
    private var hourDegree = 0f
    private var minuteDegree = 0f
    private var secondDegree = 0f

    override fun onCreate(savedInstanceState: Bundle?) {
        isMaterialActivity = true
        super.onCreate(savedInstanceState)
        setContentView(binding.root)

        updateMaterialActivityViews(binding.handsCoordinator, binding.handsHolder, useTransparentNavigation = true, useTopSearchMenu = false)
        setupMaterialScrollListener(binding.handsNestedScrollview, binding.mainToolbar)

        loadChanges()

        if (config.faceBitmap != null) {
            binding.clockBg.setColorFilter(Color.WHITE)
            Picasso.get().load(HANDS_FACE_BITMAP).into(binding.clockBg)
        }

        if (config.handsBitmap != null) {
            binding.clockHandsImage.setImageBitmap(config.handsBitmap)
        }

        if (config.framesBitmap != null) {
            Picasso.get().load(HANDS_WATCHES_FRAMES_BITMAP).into(binding.clockFrames)
        }

        binding.clockArrowHours.setColorFilter(getProperPrimaryColor())
        binding.clockArrowMinutes.setColorFilter(getProperPrimaryColor())
        binding.clockArrowSeconds.setColorFilter(getProperPrimaryColor())

        if (isBlackAndWhiteTheme()) {
            val primaryColor = getAdjustedPrimaryColor()
            binding.clockArrowHours.setColorFilter(primaryColor)
            binding.clockArrowMinutes.setColorFilter(primaryColor)
            binding.clockArrowSeconds.setColorFilter(primaryColor)
        }

        binding.handsNestedScrollview.setBackgroundColor(getProperBackgroundColor())

        binding.clockText1.setTextColor(getProperTextColor())
        binding.clockText2.setTextColor(getProperTextColor())
        binding.clockText3.setTextColor(getProperTextColor())
        binding.btnSaveChanges.apply {
            setBackgroundColor(getProperPrimaryColor())
            setTextColor(getContrastColor())
        }

        if (config.secondsBitmap == null) {
            binding.clockArrowSeconds.setColorFilter(Color.RED)
        }

        window.addFlags(WindowManager.LayoutParams.FLAG_KEEP_SCREEN_ON)
        setupToolbar(binding.mainToolbar)
        setupSensor()
        setupHoursSlider()
        setupMinutesSlider()
        setupSecondsSlider()
        updateLabelColors(binding.handsNestedScrollview, getProperTextColor())
        setSecondsDegreeAndRunClock()
    }

    private fun setupSensor() {
        sensorManager = getSystemService(Context.SENSOR_SERVICE) as SensorManager
        accelerometer = sensorManager!!.getDefaultSensor(Sensor.TYPE_ACCELEROMETER)
    }

    private fun setSecondsDegreeAndRunClock() {
        val cal = Calendar.getInstance()
        val hour = cal.get(Calendar.HOUR)
        val minutes = cal.get(Calendar.MINUTE)
        val seconds = cal.get(Calendar.SECOND)

        hourDegree = ((hour + minutes / 60.0) * 30).toFloat()
        rotateHourArrow(hourDegree)

        minuteDegree = minutes * 6f
        rotateMinuteArrow(minuteDegree)

        secondDegree = seconds * 6f
        rotateSecondsArrow(secondDegree)

        val secondsSeekBar = (secondDegree / 6)
        val minutesSeekBar = (minuteDegree / 6)
        val hoursSeekBar = (hourDegree / 30) * 6
        val hoursOutOfAllowedRange = hoursSeekBar > 360
        val hoursInRange = hoursSeekBar.coerceIn(0f, 360f)
        val progressHoursSeek = (hoursInRange / 6).toInt()
        val progressMinutesSeek = (minutesSeekBar / 6).toInt()
        val progressSecondsSeek = (secondsSeekBar / 6).toInt()

        binding.hoursSlider.progress = progressHoursSeek
        binding.minutesSlider.progress = progressMinutesSeek
        binding.secondsSlider.progress = progressSecondsSeek
    }

    private fun rotateArrow(arrow: View, oldDegrees: Float, newDegrees: Float) {
        val hourAnim = RotateAnimation(oldDegrees, newDegrees, Animation.RELATIVE_TO_SELF, 0.5f, Animation.RELATIVE_TO_SELF, 0.5f)
        hourAnim.duration = 1000
        hourAnim.fillAfter = true
        arrow.animation = hourAnim
    }

    private fun rotateHourArrow(degrees: Float) {
        rotateArrow(binding.clockArrowHours, hourDegree, degrees)
        hourDegree = degrees
        if (config.hoursOffset != degrees.roundToInt()) {
            config.hoursOffset = degrees.roundToInt()
        }
    }

    private fun rotateMinuteArrow(degrees: Float) {
        rotateArrow(binding.clockArrowMinutes, minuteDegree, degrees)
        minuteDegree = degrees
        if (config.minutesOffset != degrees.roundToInt()) {
            config.minutesOffset = degrees.roundToInt()
        }
    }

    private fun rotateSecondsArrow(degrees: Float) {
        rotateArrow(binding.clockArrowSeconds, secondDegree, degrees)
        secondDegree = degrees
        if (config.secondsOffset != degrees.roundToInt()) {
            config.secondsOffset = degrees.roundToInt()
        }
    }

    private fun setupHoursSlider() {
        binding.hoursSlider.max = 60
        binding.hoursSlider.progress = 0
        binding.hoursSlider.setOnSeekBarChangeListener(
            onProgressChanged = { _, progress, _ ->
                val newDegree = progress.toFloat() * 6
                rotateHourArrow(newDegree)
            }
        )
    }

    private fun setupMinutesSlider() {
        binding.minutesSlider.max = 60
        binding.minutesSlider.progress = 0
        binding.minutesSlider.setOnSeekBarChangeListener(
            onProgressChanged = { _, progress, _ ->
                val newDegree = progress.toFloat() * 6
                rotateMinuteArrow(newDegree)
            }
        )
    }

    private fun setupSecondsSlider() {
        binding.secondsSlider.max = 60
        binding.secondsSlider.progress = 0
        binding.secondsSlider.setOnSeekBarChangeListener(
            onProgressChanged = { _, progress, _ ->
                val newDegree = progress.toFloat() * 6
                rotateSecondsArrow(newDegree)
            }
        )
    }

    private fun saveChanges() {
        if (binding.switchAutoRotate.isChecked) {
            config.autoRotateSecondsAt = System.currentTimeMillis() + CUSTOM_SECONDS_TO_RESET.toLong()
        } else {
            config.autoRotateSecondsAt = 0L
        }
    }

    private fun loadChanges() {
        val autoRotateSecondsAt = config.autoRotateSecondsAt
        if (autoRotateSecondsAt > 0 && System.currentTimeMillis() < autoRotateSecondsAt) {
            binding.switchAutoRotate.isChecked = true
        }
    }

    override fun onPause() {
        super.onPause()
        sensorManager?.unregisterListener(this)
    }

    override fun onResume() {
        super.onResume()
        if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.KITKAT) {
            sensorManager?.registerListener(this, accelerometer, SensorManager.SENSOR_DELAY_UI)
        }
        binding.btnSaveChanges.setOnClickListener {
            saveChanges()
            if (config.recolorHandsAt < System.currentTimeMillis()) {
                config.recolorHandsAt = System.currentTimeMillis() + HANDS_RECOLOR_TIMESTAMP.toLong()
            }
            finish()
        }
    }

    override fun onCreateOptionsMenu(menu: Menu): Boolean {
        updateMenuItemColors(menu)
        return super.onCreateOptionsMenu(menu)
    }

    override fun onAccuracyChanged(sensor: Sensor?, accuracy: Int) {}

    override fun onSensorChanged(event: SensorEvent) {
        if (isSPlus()) {
            val degree = calculateDegree(event.values[0], event.values[1])
            if (!binding.switchAutoRotate.isChecked || abs(currentDegree - degree) <= 0.1f) {
                return
            }
            currentDegree = degree
            rotateBackground()
        }
    }

    private fun calculateDegree(x: Float, y: Float): Float {
        val inRadian = kotlin.math.atan2(y, x)
        return Math.toDegrees(inRadian.toDouble()).toFloat() - 90
    }

    private fun rotateBackground() {
        binding.clockHandsImage.rotation = -currentDegree
        binding.clockBg.rotation = -currentDegree
        binding.clockFrames.rotation = -currentDegree
    }
}

