            ensureBackgroundThread {
                config.apply {
                    showSecondsInClock = true
                    tabsToShow = 15
                    showIconInTabs = true
                    vibrateOnButtonPress = false
                    preventPhoneFromSleeping = true
                    showAlarmWarning = true
                    increaseVolumeGradually = true
                    startWeekWithCurrentDay = false
                    useSameSnooze = true
                    snoozeTime = 10
                    use24HourFormat = DateFormat.is24HourFormat(this@SettingsActivity)
                    sortingOrder = 0
                    alarmSort = 0
                    timerSort = 0
                    alarmMaxReminderSecs = 600
                    useTextShadow = false
                    increasing10Digits = false
                    showFirstLineInWidget = true
                    showExactTimeInWidget = false
                    passcodeLockToExit = false
                    showTabIcon = true
                    showTabLabel = true
                    tabsBgColor = -10790024
                    calendarTextColor = -592138
                    stopwatchTextColor = -1
                    timerTextColor = -1
                    timerBgColor = -10790024
                    dialTextColor = -1
                    dialBgColor = -10790024
                    iconBgColor = -10790024
                    tabsTextColor = -1
                    alarmBgColor = -10790024
                    alarmTextColor = -1
                    clockBgColor = -10790024
                    clockTextColor = -1
                    useColorfulText = false
                    isIconAutoHided = false
                    isDynamicTheme = false
