    override fun onActivityResult(requestCode: Int, resultCode: Int, resultData: Intent?) {
        super.onActivityResult(requestCode, resultCode, resultData)
        if (requestCode == GET_RINGTONE_URI && resultCode == RESULT_OK && resultData != null) {
            val newAlarmSound = storeNewAlarmSound(resultData)
            if (newAlarmSound != null) {
                when {
                    requestCode == PICK_AUDIO_FILE_INTENT_ID -> handlePickAudioFileUriResult(resultData)
                }
            }
        }
    }

