    private fun setupTabsToShow() = binding.apply {
        val tabsMask = config.displayedTabs
        if (tabsMask == 0) {
            // migrate to the new tabsToShow and displayedTabs combo
            val showClocks = config.showClock
            val showAlarms = config.showAlarms
            val showStopwatches = config.showStopwatch
            val showTimers = config.showTimer

            config.displayedTabs = if (showClocks) config.displayedTabs or TAB_CLOCK else config.displayedTabs
            config.displayedTabs = if (showAlarms) config.displayedTabs or TAB_ALARM else config.displayedTabs
            config.displayedTabs = if (showStopwatches) config.displayedTabs or TAB_STOPWATCH else config.displayedTabs
            config.displayedTabs = if (showTimers) config.displayedTabs or TAB_TIMER else config.displayedTabs
            config.tabsToShow = config.displayedTabs
        }

        val tabsText = getTabsToShowText()
        settingsTabsToShow.text = tabsText
        settingsTabsToShowHolder.setOnClickListener {
            SelectTabsToShowDialog(this@SettingsActivity) {
                val tabsText = getTabsToShowText()
                settingsTabsToShow.text = tabsText
            }
        }
    }

    private fun getTabsToShowText(): String {
        val tabs = ArrayList<String>()
        if (config.showClock) {
            tabs.add(getString(R.string.clock))
        }

        if (config.showAlarms) {
            tabs.add(getString(R.string.alarm))
        }

        if (config.showStopwatch) {
            tabs.add(getString(R.string.stopwatch))
        }

        if (config.showTimer) {
            tabs.add(getString(R.string.timer))
        }

        return tabs.joinToString(", ")
    }

