    private fun setupScrollingTimeHolder() = binding.apply {
        if (!config.useTextShadow) {
            settingsColorsScroll.isVisible = View.VISIBLE
            settingsColorsScrollLabel.isVisible = View.VISIBLE
            settingsShadowScrollLabel.isVisible = View.GONE
            settingShadow.isVisible = View.GONE
        } else {
            settingsColorsScroll.isVisible = View.GONE
            settingsColorsScrollLabel.isVisible = View.GONE
            settingsShadowScrollLabel.isVisible = View.VISIBLE
            settingShadow.isVisible = View.VISIBLE
        }

        settingShadow.isChecked = config.useTextShadow
        settingShadow.setOnClickListener {
            settingShadow.toggle()
            config.useTextShadow = settingShadow.isChecked
            setupScrollingTimeHolder()
        }

        settingsColorsScroll.isChecked = config.useColorfulText
        settingsColorsScroll.setOnClickListener {
            settingsColorsScroll.toggle()
            config.useColorfulText = settingsColorsScroll.isChecked
        }
    }

