    private fun handlePickAudioFileUriResult(resultData: Intent) {
        try {
            val pickedEffect = storeNewAlarmSound(resultData)
            val title = pickedEffect?.title
            setAlarmEffect(title)
        } catch (e: Exception) {

        }
    }

    private fun storeNewAlarmSound(resultData: Intent): AlarmSound? {
        val uri = resultData.data
        var filename = getFilenameFromUri(uri!!)
        if (filename.isEmpty()) {
            filename = getString(R.string.alarm)
        }

        val sourcePath = uri.toString()
        val destination = File(config.alarmSoundUriValue)
        if (destination.exists()) {
            destination.delete()
        }

        val filePathGetter = filePathGetter
        val localUri = try {
            filePathGetter.getLocalPath(sourcePath)
        } catch (e: Exception) {
            null
        }

        val outPath = filesDir.absolutePath.plus("/alarm/")
        File(outPath).mkdirs()
        val outFile = File(outPath, "mBellAlarmUri.mp3")
        if (outFile.exists()) {
            outFile.delete()
        }

        if (localUri !== null) {
            val alarm = AlarmSound(0, filename, outFile.absolutePath, ALARM_SOUND_TYPE_ALARM)
            try {
                if (outFile.exists()) {
                    outFile.delete()
                }
                File(localUri).copyTo(outFile, true)
                config.alarmSoundUriValue = outFile.absolutePath
                config.alarmSoundUriType = ALARM_SOUND_TYPE_ALARM
                config.alarmSoundTitle = filename
                return alarm
            } catch (e: Exception) {
                showErrorToast(e.toString())
                return null
            }
        } else {
            try {
                val inputStream = contentResolver.openInputStream(uri) ?: return null
                val outputStream = outFile.outputStream()
                inputStream.copyTo(outputStream)
                config.alarmSoundUriValue = outFile.absolutePath
                config.alarmSoundUriType = ALARM_SOUND_TYPE_ALARM
                config.alarmSoundTitle = filename
                return AlarmSound(0, filename, outFile.absolutePath, ALARM_SOUND_TYPE_ALARM)
            } catch (e: Exception) {
                showErrorToast(e.toString())
                return null
            }
        }
    }

