class AlarmReceiver : BroadcastReceiver() {

    override fun onReceive(context: Context, intent: Intent) {
        if (!context.hasAlarmsAndReminderPermission()) return

        val id = intent.getIntExtra(ALARM_ID, -1)
        val action = intent.action
        ensureBackgroundThread {
            when (action) {
                ALARM_CHANNEL_ID -> handleAlarm(context, id)
                ALARM_NOTIF_DISMISS_ACTION -> dismissAlarm(context, id)
                EARLY_ALARM_NOTIF_DISMISS_ACTION -> context.hideNotification(EARLY_ALARM_NOTIF_ID)
                ALARM_SNOOZE_ACTION -> snoozeAlarm(context, id)
                ALARM_DISMISS_ACTION_DELAYED -> dismissAlarm(context, id)
                ALARM_DISMISS_EARLY_NOTIFICATION -> context.hideNotification(EARLY_ALARM_NOTIF_ID)
                TIMER_NOTIF_DISMISS_ACTION -> context.notifyRunningTimers()
                STOPWATCH_NOTIF_DISMISS_ACTION -> context.hideNotification(TIMER_RUNNING_NOTIF_ID)
                ALARM_NOTIF_DISMISS_REMINDER -> context.hideNotification(ALARM_NOTIFICATION_ID)
                ALARM_DISMISS_NOTIFICATION -> {
                    context.hideNotification(ALARM_NOTIFICATION_ID)
                    context.hideNotification(id)
                }
            }
        }
    }

