                                .setPriority(NotificationCompat.PRIORITY_HIGH)
                                .setCategory(NotificationCompat.CATEGORY_ALARM)
                                .setContentIntent(pendingIntents.first)
                                .setSound(null)
                                .addAction(0, context.getString(R.string.dismiss), pendingIntents.second)
                                .addAction(0, context.getString(R.string.snooze), pendingIntents.third)
                                .setDeleteIntent(pendingIntents.second)
                                .setUsesChronometer(true)
                                .setColor(context.getProperPrimaryColor())

                            try {
                                notificationManager.notify(id, builder.build())
                            } catch (e: Exception) {
                                context.toast(e.message.toString())
                            }
                        }
                    }
                } catch (e: Exception) {
                    context.toast(e.message.toString())
                }
            } else {
                // screen is off, handle the alarm
                try {
                    context.grantReadUriPermission(alarm.soundUri)
                    val pendingIntent = getPendingIntent(context, alarm)
                    val reminderActivityIntent = Intent(context, ReminderActivity::class.java).apply {
                        putExtra(ALARM_ID, alarm.id)
                        addFlags(Intent.FLAG_ACTIVITY_NEW_TASK)
                    }

                    @SuppressLint("InvalidWakeLockTag")
                    val powerManager = context.getSystemService(Context.POWER_SERVICE) as PowerManager
                    val wakelock = powerManager.newWakeLock(PowerManager.FULL_WAKE_LOCK or PowerManager.ACQUIRE_CAUSES_WAKEUP, "simplealarm:wakeup")
                    wakelock.acquire(3000)

                    try {
                        context.startActivity(reminderActivityIntent)
                        Handler().postDelayed({
                            wakelock.release()
                        }, 3000)
                    } catch (e: Exception) {
                        try {
                            wakelock.release()
                        } catch (e: Exception) {}
                    }

                    Handler().postDelayed({
                        try {
                            pendingIntent.cancel()
                        } catch (e: Exception) {}
                    }, seconds * 1000)
                } catch (e: Exception) {
                    context.toast(e.message.toString())
                }
            }

            if (alarm.days == 0) {
                context.dbHelper.updateAlarmEnabledState(alarm.id, false)
            } else {
                scheduleNextAlarm(alarm, context)
            }
        }
    }

    private fun scheduleNextAlarm(alarm: com.simplemobiletools.clock.models.Alarm, context: Context) {
        val calendar = Calendar.getInstance()
        calendar.firstDayOfWeek = Calendar.MONDAY
        for (i in 0..7) {
            val currentDay = (calendar.get(Calendar.DAY_OF_WEEK) + 5) % 7
            val isCorrectDay = alarm.days and 2.0.pow(currentDay).toInt() != 0
            val currentTimeInMinutes = calendar.get(Calendar.HOUR_OF_DAY) * 60 + calendar.get(Calendar.MINUTE)
            if (isCorrectDay && (alarm.timeInMinutes > currentTimeInMinutes || i > 0)) {
                val triggerInMinutes = alarm.timeInMinutes - currentTimeInMinutes + if (i > 0) 24 * 60 else 0
                setupAlarmClock(context, alarm.id, triggerInMinutes * 60 - calendar.get(Calendar.SECOND))

                break
            } else {
                calendar.add(Calendar.DAY_OF_MONTH, 1)
            }
        }
    }

    private fun setupAlarmClock(context: Context, id: Int, triggerInSeconds: Int) {
        val alarmManager = context.getSystemService(Context.ALARM_SERVICE) as AlarmManager
        val targetMS = System.currentTimeMillis() + triggerInSeconds * 1000.toLong()
        try {
            val pendingIntent = getOpenAlarmTabIntent(context)
            val alarmPendingIntent = getPendingIntent(context, id, targetMS.toInt())
            if (isOreoPlus()) {
                val info = AlarmManager.AlarmClockInfo(targetMS, pendingIntent)
                alarmManager.setAlarmClock(info, alarmPendingIntent)
            } else {
                AlarmManager.ELAPSED_REALTIME_WAKEUP
                alarmManager.set(AlarmManager.RTC_WAKEUP, targetMS, alarmPendingIntent)
            }
        } catch (e: Exception) {
            context.toast(e.message.toString())
        }
    }

    private fun getOpenAlarmTabIntent(context: Context): PendingIntent {
        val intent = Intent(context, MainActivity::class.java)
        intent.putExtra(OPEN_INTENT_ALARM, true)
        return PendingIntent.getActivity(context, 9998, intent, PendingIntent.FLAG_UPDATE_CURRENT or PendingIntent.FLAG_IMMUTABLE)
    }

    private fun getPendingIntent(context: Context, id: Int, triggerAtMillis: Int): PendingIntent {
        val intent = Intent(context, AlarmReceiver::class.java).apply {
            action = ALARM_CHANNEL_ID
            putExtra(ALARM_ID, id)
        }
        return PendingIntent.getBroadcast(context, Random.nextInt(), intent, PendingIntent.FLAG_UPDATE_CURRENT or PendingIntent.FLAG_IMMUTABLE)
    }

    private fun getPendingIntent(context: Context, alarm: com.simplemobiletools.clock.models.Alarm): PendingIntent {
        val intent = Intent(context, AlarmReceiver::class.java).apply {
            putExtra(ALARM_ID, alarm.id)
            action = ALARM_CHANNEL_ID
        }
        val flag = if (isOreoPlus()) PendingIntent.FLAG_IMMUTABLE else 0
        return PendingIntent.getBroadcast(context, alarm.id, intent, flag)
    }

    private fun getPendingIntents(context: Context, id: Int): Triple<PendingIntent, PendingIntent, PendingIntent> {
        val intent = Intent(context, MainActivity::class.java).apply {
            putExtra(OPEN_INTENT_ALARM, true)
            putExtra(ALARM_ID, id)
            addFlags(Intent.FLAG_ACTIVITY_CLEAR_TOP)
        }
        val pendingIntent = PendingIntent.getActivity(context, id, intent, PendingIntent.FLAG_UPDATE_CURRENT or PendingIntent.FLAG_IMMUTABLE)

        val dismissIntent = Intent(context, AlarmReceiver::class.java).apply {
            action = ALARM_DISMISS_ACTION_DELAYED
            putExtra(ALARM_ID, id)
        }
        val flags = if (isOreoPlus()) PendingIntent.FLAG_IMMUTABLE else 0
        val dismissPendingIntent = PendingIntent.getBroadcast(context, id, dismissIntent, flags)

        val snoozeIntent = Intent(context, AlarmReceiver::class.java).apply {
            action = ALARM_SNOOZE_ACTION
            putExtra(ALARM_ID, id)
        }
        val snoozePendingIntent = PendingIntent.getBroadcast(context, id, snoozeIntent, flags)

        return Triple(pendingIntent, dismissPendingIntent, snoozePendingIntent)
    }

    private fun snoozeAlarm(context: Context, id: Int) {
        val alarm = context.dbHelper.getAlarmWithId(id) ?: return
        context.hideNotification(id)
        setupAlarmClock(context, alarm.id, context.config.snoozeTime * 60)
    }

    private fun dismissAlarm(context: Context, id: Int) {
        context.hideNotification(id)
        context.hideNotification(ALARM_NOTIFICATION_ID)

        val alarm = context.dbHelper.getAlarmWithId(id) ?: return
        if (alarm.days == 0) {
            context.dbHelper.updateAlarmEnabledState(alarm.id, false)
        }
        context.updateWidgets()
    }

    private fun getHideAlarmPendingIntent(context: Context, id: Int): PendingIntent {
        val intent = Intent(context, AlarmReceiver::class.java)
        intent.action = ALARM_NOTIF_DISMISS_ACTION
        intent.putExtra(ALARM_ID, id)
        return PendingIntent.getBroadcast(context, id, intent, PendingIntent.FLAG_CANCEL_CURRENT or PendingIntent.FLAG_IMMUTABLE)
    }

    private fun getHideReminderPendingIntent(context: Context): PendingIntent {
        val intent = Intent(context, AlarmReceiver::class.java)
        intent.action = ALARM_NOTIF_DISMISS_REMINDER
        return PendingIntent.getBroadcast(context, Random.nextInt(), intent, PendingIntent.FLAG_CANCEL_CURRENT or PendingIntent.FLAG_IMMUTABLE)
    }

    private fun getHideEarlyNotifPendingIntent(context: Context): PendingIntent {
        val intent = Intent(context, AlarmReceiver::class.java)
        intent.action = EARLY_ALARM_NOTIF_DISMISS_ACTION
        return PendingIntent.getBroadcast(context, Random.nextInt(), intent, PendingIntent.FLAG_CANCEL_CURRENT or PendingIntent.FLAG_IMMUTABLE)
    }

    private fun getSnoozeAlarmPendingIntent(context: Context, id: Int): PendingIntent {
        val intent = Intent(context, AlarmReceiver::class.java)
        intent.action = ALARM_SNOOZE_ACTION
        intent.putExtra(ALARM_ID, id)
        return PendingIntent.getBroadcast(context, id, intent, PendingIntent.FLAG_CANCEL_CURRENT or PendingIntent.FLAG_IMMUTABLE)
    }

    private fun Context.toast(msg: String) {
        Toast.makeText(this, msg, Toast.LENGTH_SHORT).show()
    }

    private object Random {
        private val random = java.util.Random()
        fun nextInt() = random.nextInt(100000)
    }

    companion object {
        const val ALARM_NOTIF_DISMISS_ACTION = "$PACKAGE_NAME.ALARM_NOTIF_DISMISS_ACTION"
        const val EARLY_ALARM_NOTIF_DISMISS_ACTION = "$PACKAGE_NAME.EARLY_ALARM_NOTIF_DISMISS_ACTION"
        const val ALARM_SNOOZE_ACTION = "$PACKAGE_NAME.ALARM_SNOOZE_ACTION"
        const val ALARM_DISMISS_ACTION_DELAYED = "$PACKAGE_NAME.ALARM_DISMISS_ACTION_DELAYED"
        const val ALARM_DISMISS_EARLY_NOTIFICATION = "$PACKAGE_NAME.ALARM_DISMISS_EARLY_NOTIFICATION"
        const val TIMER_NOTIF_DISMISS_ACTION = "$PACKAGE_NAME.TIMER_NOTIF_DISMISS_ACTION"
